package main

import (
	"fmt"
	"sync"
	"time"
)

type readWritePin struct {
	mu  sync.Mutex
	ttl time.Duration
	exp map[string]time.Time
}

func newReadWritePin(ttl time.Duration) *readWritePin {
	return &readWritePin{ttl: ttl, exp: make(map[string]time.Time)}
}

func (p *readWritePin) mark(account string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.exp[account] = time.Now().Add(p.ttl)
	fmt.Printf("Marked %s, expires at %v\n", account, p.exp[account])
}

func (p *readWritePin) pinned(account string) bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	exp, ok := p.exp[account]
	result := ok && time.Now().Before(exp)
	fmt.Printf("Checking %s: ok=%v, exp=%v, now=%v, pinned=%v\n", account, ok, exp, time.Now(), result)
	return result
}

func main() {
	pin := newReadWritePin(250 * time.Millisecond)
	fmt.Println("Marking account...")
	pin.mark("acct-1")

	for i := 0; i < 5; i++ {
		fmt.Printf("\n--- Check %d ---\n", i)
		result := pin.pinned("acct-1")
		fmt.Printf("Result: %v\n", result)
		time.Sleep(60 * time.Millisecond)
	}
}
EOF
